import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame()
        self.nutrition = pd.DataFrame()

    def import_strava(self, file_path):
        strava_data = pd.read_json(file_path)
        self.workouts = pd.concat([self.workouts, strava_data], ignore_index=True)

    def import_polar_flow(self, file_path):
        polar_data = pd.read_json(file_path)
        self.workouts = pd.concat([self.workouts, polar_data], ignore_index=True)

    def import_myfitnesspal(self, file_path):
        mfp_data = pd.read_json(file_path)
        self.nutrition = pd.concat([self.nutrition, mfp_data], ignore_index=True)

    def customize_view(self, sport=None):
        if sport:
            return self.workouts[self.workouts['sport'] == sport]
        return self.workouts

    def aggregate_heart_rate(self):
        zones = {'Resting': (0, 60), 'Light': (61, 120), 'Moderate': (121, 160), 'Hard': (161, 200)}
        heart_rate_zones = {zone: 0 for zone in zones.keys()}

        for index, row in self.workouts.iterrows():
            heart_rate = row['heart_rate']
            for zone, (low, high) in zones.items():
                if low <= heart_rate <= high:
                    heart_rate_zones[zone] += row['duration']
                    break

        return heart_rate_zones

    def plot_progress(self, metric='pace'):
        if metric not in ['pace', 'mileage']:
            raise ValueError("Metric must be 'pace' or 'mileage'")

        self.workouts['date'] = pd.to_datetime(self.workouts['date'])
        self.workouts.sort_values('date', inplace=True)

        plt.figure(figsize=(10, 5))
        if metric == 'pace':
            plt.plot(self.workouts['date'], self.workouts['pace'], label='Pace')
            plt.ylabel('Pace (min/km)')
        else:
            plt.plot(self.workouts['date'], self.workouts['mileage'], label='Mileage')
            plt.ylabel('Mileage (km)')

        plt.title(f'Progress Over Time by {metric.capitalize()}')
        plt.xlabel('Date')
        plt.legend()
        plt.show()

