import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'sport', 'duration', 'distance', 'calories', 'heart_rate', 'intensity_zone'])
        self.nutrition = pd.DataFrame(columns=['date', 'meal', 'calories', 'protein', 'carbs', 'fats'])

    def import_strava(self, strava_data):
        for entry in strava_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_polar_flow(self, polar_data):
        for entry in polar_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_myfitnesspal(self, mfp_data):
        for entry in mfp_data:
            self.nutrition = self.nutrition.append(entry, ignore_index=True)

    def aggregate_heart_rate(self):
        zones = {'rest': 0, 'light': 1, 'moderate': 2, 'hard': 3, 'max': 4}
        self.workouts['intensity_zone'] = pd.cut(self.workouts['heart_rate'], bins=[0, 60, 120, 160, 180, 220], labels=list(zones.keys()))
        return self.workouts.groupby('intensity_zone')['duration'].sum()

    def customize_view(self, sport=None):
        if sport:
            return self.workouts[self.workouts['sport'] == sport]
        return self.workouts

    def plot_progress(self, metric='mileage'):
        if metric == 'mileage':
            plt.plot(self.workouts['date'], self.workouts['distance'])
            plt.title('Progress by Mileage')
            plt.xlabel('Date')
            plt.ylabel('Distance (km)')
        elif metric == 'pace':
            self.workouts['pace'] = self.workouts['duration'] / self.workouts['distance']
            plt.plot(self.workouts['date'], self.workouts['pace'])
            plt.title('Progress by Pace')
            plt.xlabel('Date')
            plt.ylabel('Pace (min/km)')
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

