        user_trainings = self.user_data[user_id]['trainings']
        total_distance = sum(training['distance'] for training in user_trainings)
        total_time = sum(training['duration'] for training in user_trainings)
        max_heart_rate = max(training['max_heart_rate'] for training in user_trainings if training['max_heart_rate'] is not None)

        dashboard = {
            'total_distance_km': total_distance,
            'total_time_hours': total_time / 3600,
            'max_heart_rate': max_heart_rate,
            'training_sessions': user_trainings
        }
        return dashboard

